def lambda_handler(event, context):
    s3 = boto3.client('s3')
    sns = boto3.client('sns')

    for record in event['Records']:
        bucket = record['s3']['bucket']['name']
        key = record['s3']['object']['key']

        # Read image from S3
        image_data = s3.get_object(Bucket=bucket, Key=key)['Body'].read()

        # Process image (e.g., resize, filter)

        # Write results back to S3
        s3.put_object(Bucket=bucket, Key=key + '.processed', Body=image_data)

        # Send notification via SNS
        sns.publish(TopicArn='<topic_arn>', Message='Image processed successfully.')

    # Log to CloudWatch
    print('Image processing completed.')